function generarCopaArgentina() {
    let html = `<div class="header-t">COPA ARGENTINA 2026</div>`;

    BD_COPA_ARGENTINA_2026.forEach(r => {
        html += `<div class="header-t" style="background:#1a1a2e;color:#ffd700;font-size:11px;">${r.ronda.toUpperCase()}</div><table>`;
        r.partidos.forEach(p => {
            const escL = Object.values(BD_EQUIPOS).flat().find(e => e.nombre === p.l)?.clase || '';
            const escV = Object.values(BD_EQUIPOS).flat().find(e => e.nombre === p.v)?.clase || '';
            if (p.gl === null) {
                html += `<tr>
                    <td class="c-loc"><span style="direction:ltr;display:inline-flex;align-items:center;justify-content:flex-end;width:100%;">${p.l} <div class="escudo ${escL}" style="display:inline-block;vertical-align:middle;margin-left:4px;"></div></span></td>
                    <td class="c-res" style="font-size:10px;color:#888;">${p.dia}<br>${p.hora}</td>
                    <td class="c-vis"><div class="escudo ${escV}" style="display:inline-block;vertical-align:middle;margin-right:4px;"></div> ${p.v}</td>
                </tr>`;
                if (p.nota) html += `<tr style="background:#f5f5f5;"><td colspan="3" style="text-align:center;font-size:10px;color:#777;padding:3px 8px;font-style:italic;">📍 ${p.nota}</td></tr>`;
            } else {
                html += `<tr>
                    <td class="c-loc"><span style="direction:ltr;display:inline-flex;align-items:center;justify-content:flex-end;width:100%;">${p.l} <div class="escudo ${escL}" style="display:inline-block;vertical-align:middle;margin-left:4px;"></div></span></td>
                    <td class="c-res">${p.gl} - ${p.gv}</td>
                    <td class="c-vis"><div class="escudo ${escV}" style="display:inline-block;vertical-align:middle;margin-right:4px;"></div> ${p.v}</td>
                </tr>`;
                if (p.nota) html += `<tr style="background:#f5f5f5;"><td colspan="3" style="text-align:center;font-size:10px;color:#777;padding:3px 8px;font-style:italic;">📍 ${p.nota}</td></tr>`;
            }
if (p.goles_l?.length || p.goles_v?.length) {
    let textoGoles = "";

    if (p.goles_l?.length) {
        textoGoles += `<b>${p.l}:</b> ${p.goles_l.join(", ")}`;
    }

    if (p.goles_v?.length) {
        if (textoGoles) textoGoles += " | ";
        textoGoles += `<b>${p.v}:</b> ${p.goles_v.join(", ")}`;
    }

    html += `<tr>
        <td colspan="3" style="font-size:10px;color:#555;padding:3px 6px;text-align:center;">
            ⚽ ${textoGoles}
        </td>
    </tr>`;
}
        });
        html += `</table>`;
    });

    return html;
}


