// Reserva 1° Femenino - actualizar resultados
BD_FIXTURES.femenino.reserva.find(f => f.fecha === 1).partidos.forEach(p => {
    if (p.l === "Empleados de Comercio" && p.v === "Tiro Federal") { p.gl = 4; p.gv = 0; p.goles_l = ["Valentina Díaz","Valentina Díaz","Emilia Del Riego","Alma Acosta"]; p.goles_v = []; delete p.dia; delete p.hora; }
    if (p.l === "Sporting" && p.v === "Municipales") { p.gl = 1; p.gv = 2; delete p.dia; delete p.hora; }
    if (p.l === "Bella Vista" && p.v === "Libertad") { p.gl = 6; p.gv = 0; delete p.dia; delete p.hora; }
    if (p.l === "La Armonía" && p.v === "Villa Mitre") { p.gl = 0; p.gv = 4; delete p.dia; delete p.hora; }
});
BD_FIXTURES.femenino.reserva.find(f => f.fecha === 2).partidos.forEach(p => {
    if (p.l === "Bella Vista" && p.v === "Sporting") { p.gl = 2; p.gv = 1; p.goles_l = ["Valentina Díaz","Valentina Díaz","Emilia Del Riego","Alma Acosta"]; p.goles_v = []; delete p.dia; delete p.hora; }
    if (p.l === "Villa Mitre" && p.v === "Municipales") { p.gl = 1; p.gv = 0; delete p.dia; delete p.hora; }
    if (p.l === "Libertad" && p.v === "Empleados de Comercio") { p.gl = 0; p.gv = 2; delete p.dia; delete p.hora; }
    if (p.l === "Tiro Federal" && p.v === "La Armonía") { p.gl = 5; p.gv = 0; delete p.dia; delete p.hora; }
});
idaSegundaFemenino.forEach(f => BD_FIXTURES.segundafemenino.torneo2026.push({ fecha: f.fecha, libre: f.libre || null, partidos: f.partidos.map(p => ({...p})) }));
// Reserva 2° Femenino - sin Olimpo ni Pacífico (C)
const equiposSinReserva2Fem = ["Olimpo", "Pacífico (C)"];
idaSegundaFemenino.forEach(f => {
    const partidosFiltrados = f.partidos
        .filter(p => !equiposSinReserva2Fem.includes(p.l) && !equiposSinReserva2Fem.includes(p.v))
        .map(p => { const {dia, hora, ...rest} = {...p, gl: null, gv: null}; return rest; });
    
    // Determinar libres: el libre original + equipos que quedaron sin partido por filtro
    const sinPartido = f.partidos
        .filter(p => equiposSinReserva2Fem.includes(p.l) || equiposSinReserva2Fem.includes(p.v))
        .flatMap(p => [p.l, p.v])
        .filter(e => !equiposSinReserva2Fem.includes(e));
    
    const libres = [f.libre, ...sinPartido].filter(Boolean).join(", ");
    
    BD_FIXTURES.segundafemenino.reserva.push({ fecha: f.fecha, libre: libres || null, partidos: partidosFiltrados });
});

// Reserva 2° Femenino - resultados F1
BD_FIXTURES.segundafemenino.reserva.find(f => f.fecha === 1).partidos.forEach(p => {
    if (p.l === "San Francisco" && p.v === "Sansinena") { p.gl = 4; p.gv = 1; }
    if (p.l === "Liniers" && p.v === "Estrella de Oro") { p.gl = 3; p.gv = 1; }
});
// Reserva 2° Femenino - resultados F2
BD_FIXTURES.segundafemenino.reserva.find(f => f.fecha === 2).partidos.forEach(p => {
    if (p.l === "Sansinena" && p.v === "Rosario PB") { 
        p.gl = 1; p.gv = 3; 
        p.goles_l = ["Valentina Tobares"]; 
        p.goles_v = []
    }
    if (p.l === "Huracán" && p.v === "Liniers") { p.gl = 1; p.gv = 7; }
});


let diaSeleccionadoHome = "2026-04-02"; 

function seleccionarDiaHome(dia) {
    diaSeleccionadoHome = dia;
    actualizarVista();
}


// Metadatos de fecha: día y hora por torneo y número de fecha
const BD_FECHA_META = {
    oficial: {
        1: { dia: "DOM 15/03", hora: "16:00" }
    },
    promocional: {
        1: { dia: "SÁB 14/03 y DOM 15/03", hora: "16:00" }
    }
};

function generarHome() {
    const agenda = [
        { id: "2026-04-02", label: "JUE 02/04", torneos: [
            { nombre: "TORNEO OFICIAL", cat: "oficial", partidos: [
                {l:"Villa Mitre", v:"San Francisco", hora:"16:00"}
            ]}
        ]},
        { id: "2026-04-03", label: "VIE 03/04", torneos: [
            { nombre: "TORNEO OFICIAL", cat: "oficial", partidos: [
                {l:"La Armonía", v:"Huracán", hora:"16:00"}
            ]},
            { nombre: "TORNEO PROMOCIONAL", cat: "promocional", partidos: [
                {l:"Comercial",    v:"Dublin",      hora:"11:00"},
                {l:"Olimpo",    v:"Rosario PB",      hora:"16:00"},
                {l:"Tiro Federal",    v:"Pacífico (C)",      hora:"16:00"},
                {l:"Pacífico BB", v:"Sansinena",  hora:"16:00"}
            ]}
        ]},
        { id: "2026-04-04", label: "SÁB 04/04", torneos: [
            { nombre: "TORNEO OFICIAL", cat: "oficial", partidos: [
                {l:"Liniers", v:"Libertad", hora:"16:00"}
            ]},
        ]},
        { id: "2026-04-05", label: "DOM 05/04", torneos: [
            { nombre: "TORNEO OFICIAL", cat: "oficial", partidos: [
                {l:"Sporting", v:"Bella Vista", hora:"16:00"}
            ]},
        ]},
    ];

    let html = `<div class="nav-fechas" style="background:#222; margin-bottom:0; border-bottom:1px solid #000;">`;
    agenda.forEach(dia => {
        html += `<div class="btn-f ${diaSeleccionadoHome === dia.id ? 'active' : ''}" 
                 style="width:auto; padding:0 15px;" 
                 onclick="seleccionarDiaHome('${dia.id}')">${dia.label}</div>`;
    });
    html += `</div>`;
if (!diaSeleccionadoHome || !agenda.find(d => d.id === diaSeleccionadoHome)) {
    diaSeleccionadoHome = agenda[0].id;
}

    const diaActual = agenda.find(d => d.id === diaSeleccionadoHome);

    if (diaActual) {
        diaActual.torneos.forEach(torneo => {
            html += `<div class="header-t" style="margin-top:0; border-top:none;">${torneo.nombre}</div>`;
            html += `<table style="margin-bottom:0;">`;
            torneo.partidos.forEach(p => {
                let escL = p.claseL || BD_EQUIPOS[torneo.cat]?.find(e => e.nombre === p.l)?.clase || "";
                let escV = p.claseV || BD_EQUIPOS[torneo.cat]?.find(e => e.nombre === p.v)?.clase || "";

                // Si no hay resultado en la agenda, buscarlo en el fixture
                let gl = p.gl, gv = p.gv;
                if ((gl === undefined || gl === null) && torneo.cat !== 'copa') {
                    const fixtures = torneo.cat === 'segundafemenino'
                        ? BD_FIXTURES.segundafemenino.torneo2026
                        : torneo.cat === 'federala'
                        ? BD_FIXTURES.federala.posiciones
                        : torneo.cat === 'sub15fem'
                        ? idaSub15Fem
                        : BD_FIXTURES[torneo.cat]?.apertura || [];
                    for (const f of fixtures) {
                        const partido = f.partidos.find(x => x.l === p.l && x.v === p.v && x.gl !== null);
                        if (partido) { gl = partido.gl; gv = partido.gv; break; }
                    }
                }
                const resHome = (gl !== undefined && gl !== null) ? `${gl} - ${gv}` : '';
                html += `<tr>
                    <td style="width:50px; background:#004d26; color:#adff2f; font-weight:bold; font-size:11px; border-right:1px solid #000; text-align:center;">${p.hora}</td>
                    <td class="c-loc"><span style="direction:ltr;display:inline-flex;align-items:center;justify-content:flex-end;width:100%;">${p.l} <div class="escudo ${escL}" style="margin-left:4px;"></div></span></td>
                    <td style="width:40px; background:#fcfcfc; border-left:1px solid #eee; border-right:1px solid #eee; text-align:center; font-weight:bold; font-size:12px;">${resHome}</td>
                    <td class="c-vis"><div class="escudo ${escV}"></div> ${p.v}</td>
                    <td style="width:50px;"></td>
                </tr>`;
                if (p.nota) {
                    html += `<tr style="background:#f7f7f7;"><td colspan="5" style="font-size:8px; color:#aaa; font-style:italic; padding:1px 8px; line-height:1.2;">↳ ${p.l} vs ${p.v}: ${p.nota}</td></tr>`;
                }
            });
            html += `</table>`;
            html += `<div style="margin-bottom:12px; background:#000; padding:2px;">
                        <a href="#" onclick="navegar('apertura', '${torneo.cat}')" style="display:block; background:#00331a; color:white; text-decoration:none; text-align:center; padding:5px; font-size:10px; font-weight:bold;">Ir a sección: ${torneo.nombre}</a>
                    </div>`;
        });
    }

    return html;
}

function generarFixture(n, tor, cat) {
    const torData = BD_FIXTURES[cat][tor] || BD_FIXTURES[cat][Object.keys(BD_FIXTURES[cat])[0]];
    const f = torData.find(x => x.fecha === n) || {partidos:[]};
    const maxFechas = (cat === 'federala') ? 18 : (cat === 'segundafemenino') ? 27 : 14;
    
    let titulo = "";
    if (cat === 'federala') {
        titulo = `FEDERAL A - ZONA 4 - FECHA ${n}`;
    } else if (cat === 'oficial') {
        titulo = `TORNEO OFICIAL - FECHA ${n}`;
    } else if (cat === 'promocional') {
        titulo = `TORNEO PROMOCIONAL - FECHA ${n}`;
    } else if (cat === 'femenino') {
        titulo = `1° FEMENINO - APERTURA - FECHA ${n}`;
    } else if (cat === 'segundafemenino') {
        titulo = `2° FEMENINO - TORNEO 2026 - FECHA ${n}`;
    } else {
        titulo = `${cat.toUpperCase()} - FECHA ${n}`;
    }
    
    let html = `<div class="nav-fechas">`;
    for(let i=1; i<=maxFechas; i++) {
        html += `<div class="btn-f ${i===n?'active':''}" onclick="cambiarFecha(${i})">${i}</div>`;
    }
    html += `</div><div class="header-t">${titulo}</div><table>`;
    
    f.partidos.forEach(p => {
        const escL = BD_EQUIPOS[cat].find(e => e.nombre === p.l)?.clase || "";
        const escV = BD_EQUIPOS[cat].find(e => e.nombre === p.v)?.clase || "";
        const res = p.gl !== null ? `${p.gl} - ${p.gv}` : `-`;
        const celDia = p.dia ? `<td style="width:52px;background:#f0f0f0;text-align:center;border-right:1px solid #ddd;line-height:1.3;padding:2px 3px;"><span style="font-size:8px;color:#888;display:block;">${p.dia}</span><span style="font-size:9px;font-weight:bold;color:#333;">${p.hora}</span></td>` : `<td style="width:52px;background:#f0f0f0;border-right:1px solid #ddd;"></td>`;
        html += `<tr>${celDia}<td class="c-loc" style="width:calc(50% - 46px);"><span style="direction:ltr;display:inline-flex;align-items:center;justify-content:flex-end;width:100%;">${p.l} <div class="escudo ${escL}" style="margin-left:4px;"></div></span></td><td class="c-res">${res}</td><td class="c-vis" style="width:calc(50% - 46px);"><div class="escudo ${escV}"></div> ${p.v}</td><td style="width:52px;"></td></tr>`;
        if (p.gl !== null && ((p.goles_l && p.goles_l.length) || (p.goles_v && p.goles_v.length))) {
            // Goles en contra (e/c) se muestran del lado del equipo que recibió el gol
            const golesLMostrar = [
                ...(p.goles_l || []).filter(g => !g.includes('(e/c)')),
                ...(p.goles_v || []).filter(g => g.includes('(e/c)'))
            ];
            const golesVMostrar = [
                ...(p.goles_v || []).filter(g => !g.includes('(e/c)')),
                ...(p.goles_l || []).filter(g => g.includes('(e/c)'))
            ];
            const golesL = golesLMostrar.join(", ");
            const golesV = golesVMostrar.join(", ");
            html += `<tr style="background:#f7f7f7;"><td colspan="5" style="font-size:9px;color:#666;padding:2px 8px 3px;font-style:italic;">`;
            if (golesL) html += `⚽ ${p.l}: ${golesL}`;
            if (golesL && golesV) html += ` &nbsp;|&nbsp; `;
            if (golesV) html += `⚽ ${p.v}: ${golesV}`;
            html += `</td></tr>`;
        }
    });
    html += "</table>";
    if (f.libre) html += `<div style="padding:8px; font-size:11px; text-align:center; border-top:1px solid #eee; background:#fcfcfc; color:#555;"><b>Fecha Libre:</b> ${f.libre}</div>`;
    return html;
}

function generarTablaFederal() {
    let stats = BD_EQUIPOS.federala.map(e => ({...e, pj:0, pg:0, pe:0, pp:0, gf:0, gc:0, pts:0}));
    let partidos = BD_FIXTURES.federala.posiciones.flatMap(f => f.partidos);

    partidos.forEach(p => {
        if(p.gl !== null) {
            const l = stats.find(x => x.nombre === p.l), v = stats.find(x => x.nombre === p.v);
            l.pj++; v.pj++; l.gf += p.gl; l.gc += p.gv; v.gf += p.gv; v.gc += p.gl;
            if(p.gl > p.gv) { l.pg++; l.pts += 3; v.pp++; } 
            else if(p.gv > p.gl) { v.pg++; v.pts += 3; l.pp++; } 
            else { l.pe++; v.pe++; l.pts++; v.pts++; }
        }
    });

    stats.sort((a,b) => b.pts - a.pts || (b.gf-b.gc) - (a.gf-a.gc));

    let html = generarFixture(estado.fecha, 'posiciones', 'federala');
    html += `<div class="header-t">POSICIONES - FEDERAL A (ZONA 4)</div><table>
    <thead><tr><th style="width:25px;">#</th><th style="text-align:left;padding-left:8px;">Equipo</th><th class="c-stat">PJ</th><th class="c-stat">PG</th><th class="c-stat">PE</th><th class="c-stat">PP</th><th class="c-stat">GF</th><th class="c-stat">GC</th><th class="c-stat">Dif</th><th class="c-stat">Pts</th></tr></thead><tbody>`;
    
    stats.forEach((e, i) => {
        let cl = (i < 4) ? "p-playoff" : (i === 4) ? "p-mejorquinto" : "";
        html += `<tr class="${cl}"><td class="c-pos">${i+1}</td><td class="c-equipo">${e.nombre}</td><td class="c-stat">${e.pj}</td><td class="c-stat">${e.pg}</td><td class="c-stat">${e.pe}</td><td class="c-stat">${e.pp}</td><td class="c-stat">${e.gf}</td><td class="c-stat">${e.gc}</td><td class="c-stat">${e.gf-e.gc}</td><td class="c-stat"><b>${e.pts}</b></td></tr>`;
    });
    
    const mejoresQuintos = [
        { nombre: "Alvarado", pj:2, pg:1, pe:0, pp:1, gf:2, gc:2 },
        { nombre: "Defensores Pto. Vilelas", pj:2, pg:1, pe:0, pp:1, gf:2, gc:2 },
        { nombre: "Argentino (MM)", pj:2, pg:0, pe:2, pp:0, gf:0, gc:0 }
    ];
    html += `</tbody></table><div class="header-t">MEJORES 5° (ZONAS 2, 3 Y 4)</div>`;
    html += `<table><thead><tr><th style="width:25px;">#</th><th style="text-align:left;padding-left:8px;">Equipo</th><th class="c-stat">PJ</th><th class="c-stat">PG</th><th class="c-stat">PE</th><th class="c-stat">PP</th><th class="c-stat">GF</th><th class="c-stat">GC</th><th class="c-stat">Dif</th><th class="c-stat">Pts</th></tr></thead><tbody>`;
    mejoresQuintos.forEach((e, i) => {
        const dif = e.gf - e.gc;
        const pts = e.pg * 3 + e.pe;
        const cl = i === 0 ? "p-playoff" : "";
        html += `<tr class="${cl}"><td class="c-pos">${i+1}</td><td class="c-equipo">${e.nombre}</td><td class="c-stat">${e.pj}</td><td class="c-stat">${e.pg}</td><td class="c-stat">${e.pe}</td><td class="c-stat">${e.pp}</td><td class="c-stat">${e.gf}</td><td class="c-stat">${e.gc}</td><td class="c-stat">${dif > 0 ? '+'+dif : dif}</td><td class="c-stat"><b>${pts}</b></td></tr>`;
    });
    return html + `</tbody></table>`;
}

