function generarSub() {
    const categorias = [
        { key: 'sub13', label: 'SUB-13' },
        { key: 'sub15', label: 'SUB-15' },
        { key: 'sub17', label: 'SUB-17' }
    ];

    let html = `<div class="header-t">FEDERAL A — SUB 13/15/17</div>
    <style>
        .sub-cat-header { background:#00331a; color:#adff2f; font-size:11px; font-weight:bold;
            padding:7px 10px; display:flex; align-items:center; cursor:pointer;
            user-select:none; border-bottom:1px solid #005522; }
        .sub-cat-header:hover { background:#004d20; }
        .sub-cat-arrow { margin-left:auto; font-size:10px; transition:transform 0.2s; }
        .sub-cat-arrow.open { transform:rotate(90deg); }
        .sub-cat-body { display:none; }
        .sub-cat-body.open { display:block; }
    </style>`;

    categorias.forEach(cat => {
        const fixtures = BD_FIXTURES_SUB[cat.key] || [];
        const n = estado[`fecha_${cat.key}`] || 2;
        const f = fixtures.find(x => x.fecha === n) || { partidos: [], libre: null };

        // Posiciones manuales
        const stats = BD_POS_SUB[cat.key] || BD_EQUIPOS_SUB.map(e => ({...e, pj:0, pg:0, pe:0, pp:0, gf:0, gc:0, pts:0}));

        html += `
        <div class="sub-cat-header" onclick="toggleSubCat('${cat.key}')">
            <span>${cat.label}</span>
            <span class="sub-cat-arrow" id="arr-${cat.key}">▶</span>
        </div>
        <div class="sub-cat-body" id="body-${cat.key}">`;

        // Nav fechas
        html += `<div class="nav-fechas">`;
        for (let i = 1; i <= 14; i++) {
            const activa = i === n ? 'activa' : '';
            html += `<div class="btn-f ${activa}" onclick="cambiarFechaSub(${i},'${cat.key}')">${i}</div>`;
        }
        html += `</div>`;

        // Fixture
        html += `<div class="header-t">${cat.label} — FECHA ${n}</div>`;
        if (f.libre) html += `<div style="padding:6px 10px;font-size:11px;background:#f9f9f9;border-bottom:1px solid #eee;"><b>Fecha libre:</b> ${f.libre}</div>`;
        html += `<table>`;
        f.partidos.forEach(p => {
            const escL = BD_EQUIPOS_SUB.find(e => e.nombre === p.l)?.clase || '';
            const escV = BD_EQUIPOS_SUB.find(e => e.nombre === p.v)?.clase || '';
            const res = p.gl !== null ? `${p.gl} - ${p.gv}` : '- -';
            html += `<tr>
                <td class="c-loc"><span style="direction:ltr;display:inline-flex;align-items:center;justify-content:flex-end;width:100%;">${p.l} <div class="escudo ${escL}" style="display:inline-block;vertical-align:middle;margin-left:4px;"></div></span></td>
                <td class="c-res">${res}</td>
                <td class="c-vis"><div class="escudo ${escV}" style="display:inline-block;vertical-align:middle;margin-right:4px;"></div> ${p.v}</td>
            </tr>`;
        });
        html += `</table>`;

        // Posiciones
        html += `<div class="header-t">POSICIONES — ${cat.label}</div>
        <table><thead><tr>
            <th style="width:25px;">#</th>
            <th style="text-align:left;padding-left:8px;">Equipo</th>
            <th class="c-stat">PJ</th><th class="c-stat">PG</th><th class="c-stat">PE</th>
            <th class="c-stat">PP</th><th class="c-stat">GF</th><th class="c-stat">GC</th>
            <th class="c-stat">Dif</th><th class="c-stat">Pts</th>
        </tr></thead><tbody>`;
        stats.forEach((e, i) => {
            const dif = (e.gf || 0) - (e.gc || 0);
            html += `<tr>
                <td class="c-pos">${i+1}</td>
                <td class="c-equipo"><div class="escudo ${e.clase}" style="display:inline-block;vertical-align:middle;margin-right:4px;"></div>${e.nombre}</td>
                <td class="c-stat">${e.pj||0}</td><td class="c-stat">${e.pg||0}</td><td class="c-stat">${e.pe||0}</td>
                <td class="c-stat">${e.pp||0}</td><td class="c-stat">${e.gf||0}</td><td class="c-stat">${e.gc||0}</td>
                <td class="c-stat">${dif > 0 ? '+'+dif : dif}</td><td class="c-stat"><b>${e.pts||0}</b></td>
            </tr>`;
        });
        html += `</tbody></table>`;

        // Goleadores
        html += `<div class="header-t">GOLEADORES — ${cat.label}</div>`;
        const goles = BD_GOL_SUB[cat.key] || [];
        if (goles.length === 0) {
            html += `<div class="msg-prox" style="padding:10px;text-align:center;font-size:11px;color:#999;">Sin goles registrados aún</div>`;
        } else {
            html += `<table><thead><tr>
                <th style="width:25px;">#</th>
                <th style="text-align:center;">Jugador</th>
                <th style="text-align:center;">Equipo</th>
                <th class="c-stat">Goles</th>
            </tr></thead><tbody>`;
            let pos = 1, prev = -1;
            goles.forEach((g, i) => {
                if (g.n !== prev) { pos = i + 1; prev = g.n; }
                html += `<tr>
                    <td class="c-pos">${pos}°</td>
                    <td style="text-align:center;font-size:11px;">${g.jugador}</td>
                    <td style="text-align:center;font-size:11px;"><div class="escudo ${g.clase}" style="display:inline-block;vertical-align:middle;margin-right:4px;"></div>${g.equipo}</td>
                    <td class="c-stat"><b>${g.n}</b></td>
                </tr>`;
            });
            html += `</tbody></table>`;
        }

        html += `</div>`; // cierre sub-cat-body
    });

    return html;
}


